rules.rule_text:
rule IsPE32 : PECheck
{
	condition:
		uint16( 0 ) == 0x5A4D and uint16( uint32( 0x3C ) + 0x18 ) == 0x010B
}

rule IsPE64 : PECheck
{
	condition:
		uint16( 0 ) == 0x5A4D and uint16( uint32( 0x3C ) + 0x18 ) == 0x020B
}

import "pe"

rule IsNET_EXE : PECheck
{
	condition:
		pe.imports( "mscoree.dll" , "_CorExeMain" )
}

import "pe"

rule IsNET_DLL : PECheck
{
	condition:
		pe.imports( "mscoree.dll" , "_CorDllMain" )
}

rule IsDLL : PECheck
{
	condition:
		uint16( 0 ) == 0x5A4D and ( uint16( uint32( 0x3C ) + 0x16 ) & 0x2000 ) == 0x2000
}

rule IsConsole : PECheck
{
	condition:
		uint16( 0 ) == 0x5A4D and uint16( uint32( 0x3C ) + 0x5C ) == 0x0003
}

rule IsWindowsGUI : PECheck
{
	condition:
		uint16( 0 ) == 0x5A4D and uint16( uint32( 0x3C ) + 0x5C ) == 0x0002
}

import "pe"

rule PureBasicDLL : Neil Hodgson
{
	meta:
		author = "malware-lu"

	strings:
		$a0 = { 83 7C 24 08 01 75 ?? 8B 44 24 04 A3 ?? ?? ?? 10 E8 }

	condition:
		$a0 at pe.entry_point
}

